effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

vec4 composite( vec4 a, vec4 b) {
    return a * (1. - b.a) + b;
}

vec4 blurInternal(vec2 texOffset, vec2 st, float numBlurPixelsPerSide)
{
    if(strength <= 0.0)
        return vec4(0,0,0,0);
    const float PI = 3.14159265;
    //To get gauss(x) <= gauss(0)*0.1
    //x>=sigma*sqrt(2*ln10) = 2.14596602...
    //If you want to get gauss(x) <= gauss(0)*0.01 to get more dedicated result,
    //x>=2.0*sigma*sqrt(ln10) = 3.03485425....
    //currently, in my thought, 0.1 of the center pixel will be enough.
    float adjSigma = numBlurPixelsPerSide / 2.14596602;


    highp vec3 incrementalGaussian;
    incrementalGaussian.x = 1.0 / (sqrt(2.0 * PI) * adjSigma);
    incrementalGaussian.y = exp(-0.5 / (adjSigma * adjSigma));
    incrementalGaussian.z = incrementalGaussian.y * incrementalGaussian.y;

    vec4 avgValue = vec4(0.0, 0.0, 0.0, 0.0);
    highp float coefficientSum = 0.0;

    avgValue += ((acPass==1 ? texture2DCv(downImg.texture,st) : texture2DCv(hblur.texture,st)).rgba * incrementalGaussian.x);
    coefficientSum += incrementalGaussian.x;

    for (float i = 1.0; i <= numBlurPixelsPerSide; i += 2.0) {

        float offset0 = i;
        float offset1 = i + 1.0;

        incrementalGaussian.xy *= incrementalGaussian.yz;
        coefficientSum += (2.0 * incrementalGaussian.x);
        float weight0 = incrementalGaussian.x;
        incrementalGaussian.xy *= incrementalGaussian.yz;
        coefficientSum += (2.0 * incrementalGaussian.x);
        float weight1 = incrementalGaussian.x;
        float weightL = weight0 + weight1;
        float offsetL = (offset0*weight0 + offset1*weight1) / weightL;
        vec2 stL = clamp(st - offsetL * texOffset, vec2(0.0, 0.0), vec2(1.0,1.0));
        vec2 stR = clamp(st + offsetL * texOffset, vec2(0.0, 0.0), vec2(1.0, 1.0));
        avgValue += ((acPass==1 ? texture2DCv(downImg.texture,stL) : texture2DCv(hblur.texture,stL)) * weightL);
        avgValue += ((acPass==1 ? texture2DCv(downImg.texture,stR) : texture2DCv(hblur.texture,stR)) * weightL);
    }

    return avgValue / coefficientSum;
}
void main() {
    if( acPass == 0 ) {
        vec4 c = texture2DCv(inputImg.texture, acScreenNorm.st);
        float luminance = dot(c.rgb, luminanceWeighting);
        gl_FragColor = (luminance > threshold) ? mix(c,color*c.a,blend) : vec4(0.);
    }
    else if( acPass==1 ) {
        float kernelSize = strength / 2.0 * 1.14 / 4.0 / 3.0 * length(acPreviewSize);
        vec2 texOffset = vec2(1.0/downImg.size.x, 0.0);
        gl_FragColor = blurInternal(texOffset, acScreenNorm.st, kernelSize);
    } else if( acPass==2 ) {
        float kernelSize = strength / 2.0 * 1.14 / 4.0 / 3.0 * length(acPreviewSize);
        vec2 texOffset = vec2(0.0, 1.0/hblur.size.y);
        vec4 base = texture2DCv(inputImg.texture, acScreenNorm.st);
        vec4 result;
        if(strength <= 0.0) {
            float luminance = dot(base.rgb, luminanceWeighting);
            result = (luminance > threshold) ? mix(base,color*base.a,blend) : vec4(0.);
        } else {
            result = blurInternal(texOffset, acScreenNorm.st, kernelSize);
        }
        vec3 aa = result.rgb/max(result.a,0.0001)*intensity;

        float hsqueeze = 0.15;
        float h = (1.-smoothstep(0.,hsqueeze,abs(result.a-hsqueeze)))*halo;
        vec3 hh = mix(aa/hsqueeze*halo,color.rgb*halo,blend);
        aa += hh*h;

        vec3 bb = base.rgb/max(base.a,0.0001);
        vec3 rgb = 1.-((1.-aa) * (1.-bb));
        gl_FragColor = composite(base,vec4(rgb,1)*min(base.a,result.a)*alpha);
    } else {
        gl_FragColor = texture2DCv(vblur.texture, acScreenNorm.st);
    }
}
